def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    """
    {This algorithm selects the next customer node for the truck by prioritizing customers within their time windows with the smallest time penalty,
    then the node closest to the current truck position while considering overall minimization of the last truck return time.}
    """

    def distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    min_time_penalty = float('inf')
    best_node = None
    min_distance = float('inf')

    for i, customer in enumerate(unvisited_customers):
        travel_time = distance(cur_truck_pos, customer) / truck_speed
        arrival_time = current_time + travel_time
        window_start, window_end = time_windows[i]

        if arrival_time > window_end:
            time_penalty = arrival_time - window_end
        else:
            time_penalty = max(0, window_start - arrival_time)

        if time_penalty < min_time_penalty or (time_penalty == min_time_penalty and distance(cur_truck_pos, customer) < min_distance):
