# {Apply a probabilistic approach using stochastic modeling to estimate the costs and deviations in travel and time window adherence, adjusting the node selection strategy based on dynamic expectations.}
def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    np.random.seed(0)
    best_node = None
    min_expected_cost = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = euclidean_distance(cur_truck_pos, customer_pos) / truck_speed
        arrival_time = current_time + travel_time

        start_time, end_time = time_windows[i]

        if arrival_time < start_time:
            wait_time = start_time - arrival_time
            penalty = 0
        else:
            wait_time = 0
            if arrival_time > end_time:
                penalty = (arrival_time - end_time) * 1000
            else:
                penalty = 0

        stochastic_factor = np.random.normal(loc=0.0, scale=0.1)
        expected_cost = (travel_time + wait_time + penalty) * (1 + stochastic_factor)

        if expected_cost < min_expected_cost:
            min_expected_cost = expected_cost
            best_node = i

    return best_node
